1	/** A live cell's position as [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
5	  [-1, -1], [-1, 0], [-1, 1],
6	  [ 0, -1],          [ 0, 1],
7	  [ 1, -1], [ 1, 0], [ 1, 1],
8	];
9	
10	const neighborsOf = ([x, y]: Cell): Cell[] =>
11	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
12	
13	const survives = (neighborCount: number, wasAlive: boolean): boolean =>
14	  neighborCount === 3 || (neighborCount === 2 && wasAlive);
15	
16	/**
17	 * Computes the next generation of Conway's Game of Life.
18	 * Returns the set of cells that will be alive in the next tick.
19	 */
20	export function nextGeneration(cells: Cell[]): Cell[] {
21	  const alive = new Set(cells.map(String));
22	  const tally = new Map<string, { cell: Cell; count: number }>();
23	
24	  for (const cell of cells.flatMap(neighborsOf)) {
25	    const key = String(cell);
26	    const prev = tally.get(key)?.count ?? 0;
27	    tally.set(key, { cell, count: prev + 1 });
28	  }
29	
30	  return [...tally.values()]
31	    .filter(({ cell, count }) => survives(count, alive.has(String(cell))))
32	    .map(({ cell }) => cell);
33	}
34

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each with one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) stable as a still life", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should transform a vertical blinker into a horizontal blinker", () => {
20	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
21	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect(result.sort()).toEqual(expected.sort());
24	  });
25	  it("should kill a cell with more than 3 neighbors (overpopulation)", () => {
26	    // Center cell (1,1) has 4 live neighbors → should die
27	    const cells: [number, number][] = [
28	      [0, 0], [1, 0], [2, 0],
29	      [0, 1], [1, 1], [2, 1],
30	    ];
31	    const result = nextGeneration(cells);
32	    expect(result).not.toContainEqual([1, 1]);
33	  });
34	  it("should bring a dead cell with exactly 3 neighbors to life (reproduction)", () => {
35	    // L-shape: dead cell (1,1) has exactly 3 live neighbors → becomes alive
36	    const cells: [number, number][] = [[0, 0], [1, 0], [0, 1]];
37	    const result = nextGeneration(cells);
38	    expect(result).toContainEqual([1, 1]);
39	  });
40	  it("should handle negative coordinates correctly", () => {
41	    // Blinker at negative coordinates: vertical → horizontal
42	    const vertical: [number, number][] = [[-5, -1], [-5, 0], [-5, 1]];
43	    const expected: [number, number][] = [[-6, 0], [-5, 0], [-4, 0]];
44	    const result = nextGeneration(vertical);
45	    expect(result.sort()).toEqual(expected.sort());
46	  });
47	});
